import React from 'react';
import { Box, IconButton, Paper, Typography } from '@mui/material';
import { Delete as DeleteIcon, AddPhotoAlternate as AddPhotoIcon } from '@mui/icons-material';
import { motion } from 'framer-motion';

const MotionPaper = motion(Paper);

const PhotoBookPage = ({ 
    format,
    pageWidth,
    pageHeight,
    photos = [],
    availablePhotos = [],
    onPhotoAdd,
    onPhotoRemove,
    onPhotoEdit
}) => {
    const handleDrop = (e, position) => {
        e.preventDefault();
        const photoData = e.dataTransfer.getData('photo');
        if (photoData) {
            const photo = JSON.parse(photoData);
            onPhotoAdd(position, photo);
        }
    };

    const handleDragOver = (e) => {
        e.preventDefault();
        e.currentTarget.style.backgroundColor = 'rgba(0, 0, 0, 0.1)';
    };

    const handleDragLeave = (e) => {
        e.preventDefault();
        e.currentTarget.style.backgroundColor = 'transparent';
    };

    return (
        <Box sx={{ mb: 4 }}>
            <Typography variant="h6" gutterBottom align="center">
                Страница
            </Typography>
            <MotionPaper
                elevation={3}
                sx={{
                    width: pageWidth,
                    height: pageHeight,
                    margin: '0 auto',
                    position: 'relative',
                    display: 'grid',
                    gridTemplateColumns: 'repeat(2, 1fr)',
                    gridTemplateRows: 'repeat(2, 1fr)',
                    gap: 1,
                    p: 1,
                    bgcolor: 'background.paper'
                }}
            >
                {[0, 1, 2, 3].map((position) => {
                    const photo = photos.find(p => p.position === position);

                    return (
                        <Box
                            key={position}
                            sx={{
                                position: 'relative',
                                border: '1px dashed',
                                borderColor: photo ? 'transparent' : 'grey.300',
                                borderRadius: 1,
                                overflow: 'hidden',
                                bgcolor: 'transparent',
                                transition: 'all 0.2s ease-in-out',
                                '&:hover': {
                                    '& .photo-controls': {
                                        opacity: 1
                                    }
                                }
                            }}
                            onDrop={(e) => handleDrop(e, position)}
                            onDragOver={handleDragOver}
                            onDragLeave={handleDragLeave}
                        >
                            {photo ? (
                                <>
                                    <img
                                        src={photo.preview || photo.url}
                                        alt={`Photo ${photo.id}`}
                                        style={{
                                            width: '100%',
                                            height: '100%',
                                            objectFit: 'cover'
                                        }}
                                    />
                                    <Box
                                        className="photo-controls"
                                        sx={{
                                            position: 'absolute',
                                            top: 0,
                                            right: 0,
                                            p: 0.5,
                                            opacity: 0,
                                            transition: 'opacity 0.2s ease-in-out',
                                            bgcolor: 'rgba(0, 0, 0, 0.5)',
                                            borderRadius: '0 0 0 4px'
                                        }}
                                    >
                                        <IconButton
                                            size="small"
                                            onClick={() => onPhotoRemove(position)}
                                            sx={{ 
                                                color: 'white',
                                                '&:hover': {
                                                    bgcolor: 'error.main'
                                                }
                                            }}
                                        >
                                            <DeleteIcon fontSize="small" />
                                        </IconButton>
                                    </Box>
                                </>
                            ) : (
                                <Box
                                    sx={{
                                        width: '100%',
                                        height: '100%',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center',
                                        color: 'text.secondary',
                                        fontSize: '0.75rem'
                                    }}
                                >
                                    <AddPhotoIcon sx={{ fontSize: 30 }} />
                                </Box>
                            )}
                        </Box>
                    );
                })}
            </MotionPaper>
        </Box>
    );
};

export default PhotoBookPage;
